            // Update frequency
            frequency[char] = (frequency[char] || 0) + 1;

            // Record first appearance if not seen before
            if (!(char in firstAppearance)) {
                firstAppearance[char] = i;
            }
        }
    }

    // 2. Identify unique vowels and prepare for sorting
    const uniqueVowels = Object.keys(frequency);

    // 3. Sort the unique vowels
    // Primary sort: Frequency descending (a - b)
    // Secondary sort: First appearance ascending (a - b)
