    let result = [];

    for (let i = 0; i < N; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Replace the vowel with the next element from the sorted sequence
            result.push(replacementSequence[seqPointer]);
            seqPointer++;
        } else {
            // Consonants remain unchanged
            result.push(char);
