import scala.collection.mutable

def solve(s: String): String = {
    val vowels: Set[Char] = Set('a', 'e', 'i', 'o', 'u')
    val N = s.length

    // 1. Collect frequency and first appearance index
    val frequency = mutable.Map[Char, Int]()
    val firstAppearance = mutable.Map[Char, Int]()

    for (i <- 0 until N) {
        val char = s(i)
        if (vowels.contains(char)) {
            // Update frequency
            frequency.update(char, frequency.getOrElse(char, 0) + 1)

            // Record first appearance if not seen before
            if (!firstAppearance.contains(char)) {
                firstAppearance.put(char, i)
            }
        }
    }

    // 2. Identify unique vowels and prepare for sorting
    val uniqueVowels = frequency.keys.toList

    // 3. Sort the unique vowels
    // Primary sort: Frequency descending (using negative frequency for ascending sort)
    // Secondary sort: First appearance ascending
    val sortedVowels = uniqueVowels.sortBy { vowel =>
        val freq = frequency(vowel)
        val index = firstAppearance(vowel)
        // Sort key: (-Frequency, FirstIndex)
        (-freq, index)
    }

    // 4. Build the replacement sequence
    var replacementSequence = List.empty[Char]
    for (vowel <- sortedVowels) {
        val count = frequency(vowel)
        replacementSequence = replacementSequence ++ List.fill(count)(vowel)
    }

    // 5. Construct the result string
    var seqPointer = 0
    val resultBuilder = new StringBuilder(N)

    for (i <- 0 until N) {
        val char = s(i)
        if (vowels.contains(char)) {
            // Replace the vowel with the next element from the sorted sequence
            // We assume replacementSequence has exactly the right number of elements
            resultBuilder.append(replacementSequence(seqPointer))
            seqPointer += 1
        } else {
            // Consonants remain unchanged
            resultBuilder.append(char)
        }
    }

    resultBuilder.toString
}

